// Validate Data Completeness
// Outputs field names that EXACTLY match Excel column headers for autoMap

const extractedData = $json.output || {};

// DEFENSIVE PARSING: If Structured Output Parser failed (onError: continueRegularOutput),
// aiAnalysis will be a STRING instead of an object. Detect and parse it.
let aiAnalysis = $('AI Recruiter Analysis').item.json.output || {};

if (typeof aiAnalysis === 'string') {
  try {
    // Strip markdown code fences if present
    let cleaned = aiAnalysis.trim();
    if (cleaned.startsWith('```')) {
      cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '');
    }
    cleaned = cleaned.trim();
    aiAnalysis = JSON.parse(cleaned);
  } catch (e) {
    // If direct parse fails, try to extract the outermost JSON object
    try {
      const str = aiAnalysis;
      // Find first { and last }
      const firstBrace = str.indexOf('{');
      const lastBrace = str.lastIndexOf('}');
      if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        const jsonCandidate = str.substring(firstBrace, lastBrace + 1);
        aiAnalysis = JSON.parse(jsonCandidate);
      } else {
        aiAnalysis = {};
      }
    } catch (e2) {
      // All parsing failed - use empty object, fields will be empty
      aiAnalysis = {};
    }
  }
}

// Also check if output is nested in an unexpected wrapper
if (aiAnalysis.output && typeof aiAnalysis.output === 'object' && aiAnalysis.output.candidate_strengths) {
  aiAnalysis = aiAnalysis.output;
}

const transformData = $('Transform to Workflow Format').item.json || {};
const standardizedData = $('Standardize Resume Data').item.json || {};

// CONTACT INFO - Use Paycor as PRIMARY source (more reliable than AI extraction)
const full_name = standardizedData.paycor_full_name || transformData.body?.candidateName || extractedData.full_name || 'Unknown';
const email_address = standardizedData.paycor_email || transformData.body?.email || extractedData.email_address || '';
const phone_number = standardizedData.paycor_phone || transformData.body?.phone || extractedData.phone_number || '';

// AI EXTRACTION FIELDS - Now from aiAnalysis instead of extractedData
const current_title = aiAnalysis.current_title || '';
const years_experience = aiAnalysis.years_experience || '';
const key_skills = aiAnalysis.key_skills || '';

// PAYCOR ANALYTICS FIELDS
const source = standardizedData.source || '';
const applied_date = standardizedData.applied_date || '';
const pipeline_stage = standardizedData.pipeline_stage ?? 0;
const candidate_status = standardizedData.candidate_status ?? 3;
const candidate_city = standardizedData.candidate_city || '';
const candidate_state = standardizedData.candidate_state || '';

// AI ANALYSIS FIELDS
const overall_score = aiAnalysis.overall_score || 0;
const matched_job_title = aiAnalysis.matched_job_title || '';
const candidate_strengths = aiAnalysis.candidate_strengths || [];
const candidate_weaknesses = aiAnalysis.candidate_weaknesses || [];
const risk_level = aiAnalysis.risk_assessment?.level || '';
const risk_explanation = aiAnalysis.risk_assessment?.explanation || '';
const opportunity_level = aiAnalysis.opportunity_assessment?.level || '';
const opportunity_explanation = aiAnalysis.opportunity_assessment?.explanation || '';
const ai_adoption_level = aiAnalysis.ai_adoption_assessment?.level || '';
const ai_adoption_explanation = aiAnalysis.ai_adoption_assessment?.explanation || '';
const score_justification = aiAnalysis.score_justification || '';
const recruiter_note = aiAnalysis.recruiter_note || '';
const next_steps = aiAnalysis.next_steps_recommendation || '';

// METADATA FIELDS
const resume_link = standardizedData.driveLink || '';
const candidateId = transformData.body?.candidateId || '';
const jobId = transformData.body?.jobId || '';
const resumeText = standardizedData.resumeText || '';
const jobTitle = standardizedData.jobTitle || '';

// TIMESTAMPS
const now = new Date().toISOString();

// CRITICAL: Name + Email + Score (per user preference)
const CRITICAL_FIELDS = { full_name, email_address, overall_score };

// Check for missing fields
const missingCritical = [];
const missingOptional = [];

for (const [field, value] of Object.entries(CRITICAL_FIELDS)) {
  if (value === undefined || value === null || value === '') {
    missingCritical.push(field);
  }
}

const isComplete = missingCritical.length === 0;

// Get operation from earlier deduplication
const operation = $('Transform to Workflow Format').item.json._operation || 'INSERT';
const compositeKey = $('Transform to Workflow Format').item.json._compositeKey ||
  `${transformData.body?.candidateId}_${transformData.body?.jobId}`;

// Format arrays as strings for Excel
const strengthsStr = Array.isArray(candidate_strengths) ? candidate_strengths.join(' | ') : candidate_strengths;
const weaknessesStr = Array.isArray(candidate_weaknesses) ? candidate_weaknesses.join(' | ') : candidate_weaknesses;

return [{
  json: {
    // ===== EXCEL COLUMN NAMES (EXACT MATCH REQUIRED) =====

    // Row 1-4: Source & Dates
    source: source,
    Date: now.split('T')[0],
    applied_date: applied_date,
    pipeline_stage: pipeline_stage,

    // Row 5-8: Candidate Info
    Candidate_Name: full_name,
    candidate_status: candidate_status,
    candidate_city: candidate_city,
    candidate_state: candidate_state,

    // Row 9-13: Contact & Skills
    Email: email_address,
    Phone: phone_number,
    Current_Title: current_title,
    Years_Experience: years_experience,
    Key_Skills: key_skills,

    // Row 14-16: Job Info
    Job_ID: jobId,
    Matched_Job_Title: matched_job_title,
    Overall_Score: overall_score,

    // Row 17-18: Strengths/Weaknesses
    Strengths: strengthsStr,
    Weaknesses: weaknessesStr,

    // Row 19-22: Risk & Opportunity
    Risk_Level: risk_level,
    Risk_Details: risk_explanation,
    Opportunity_Level: opportunity_level,
    Opportunity_Details: opportunity_explanation,

    // Row 23-24: Justification & Next Steps
    Justification: score_justification,
    Next_Steps: next_steps,

    // Row 25-26: Resume & Dates
    resumeText: resumeText.substring(0, 32000),
    Evaluated_Date: now,

    // Row 27-29: IDs
    candidateId: candidateId,
    jobId: jobId,
    paycorJobTitle: jobTitle,

    // Row 30-32: AI Adoption & Key
    AI_Adoption_Level: ai_adoption_level,
    AI_Adoption_Details: ai_adoption_explanation,
    compositeKey: compositeKey,

    // ===== INTERNAL FIELDS (for downstream nodes) =====
    full_name: full_name,
    email_address: email_address,
    phone_number: phone_number,
    current_title: current_title,
    years_experience: years_experience,
    key_skills: key_skills,
    overall_score: overall_score,
    matched_job_title: matched_job_title,
    candidate_strengths: candidate_strengths,
    candidate_weaknesses: candidate_weaknesses,
    risk_level: risk_level,
    risk_explanation: risk_explanation,
    opportunity_level: opportunity_level,
    opportunity_explanation: opportunity_explanation,
    ai_adoption_level: ai_adoption_level,
    ai_adoption_explanation: ai_adoption_explanation,
    score_justification: score_justification,
    recruiter_note: recruiter_note,
    next_steps: next_steps,
    resume_link: resume_link,

    // ORIGINAL PASSTHROUGH DATA
    output: extractedData,
    aiOutput: aiAnalysis,
    transformData: transformData,
    standardizedData: standardizedData,
    _operation: operation,
    _compositeKey: compositeKey,

    // COMPLETENESS METADATA
    completeness: {
      status: isComplete ? 'COMPLETE' : 'INCOMPLETE',
      isComplete: isComplete,
      missingCritical: missingCritical,
      missingOptional: missingOptional,
      missingFields: [...missingCritical, ...missingOptional].join(', '),
      criticalCount: missingCritical.length,
      optionalCount: missingOptional.length,
      totalMissing: missingCritical.length + missingOptional.length
    }
  }
}];

// Format date for executive readability: YYYY-MM-DD HH:MM AM/PM
function formatDate(isoString) {
  if (!isoString) return 'N/A';
  const date = new Date(isoString);
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  let hours = date.getHours();
  const minutes = String(date.getMinutes()).padStart(2, '0');
  const ampm = hours >= 12 ? 'PM' : 'AM';
  hours = hours % 12;
  hours = hours ? hours : 12; // 0 should be 12
  return `${year}-${month}-${day} ${hours}:${minutes} ${ampm}`;
}

// Prepare Email Data
// FIXED: Data comes from Validate Data Completeness which outputs fields at TOP LEVEL
// NOTE: Merge After Logging may output 2 items - use the FIRST one (from Validate Data Completeness)

const items = $input.all();

// Find the item with proper candidate data (has full_name field)
const candidateItem = items.find(item => item.json.full_name && item.json.full_name !== '');

if (!candidateItem) {
  // Fallback to first item if no candidate data found
  console.log('Warning: No candidate item found with full_name');
  return [{ json: { error: true, message: 'No valid candidate data found' } }];
}

const data = candidateItem.json;

// PRIMARY: Use top-level fields from Validate Data Completeness
const full_name = data.full_name || 'Unknown';
const email_address = data.email_address || '';
const phone_number = data.phone_number || '';
const current_title = data.current_title || '';
const years_experience = data.years_experience || '';
const key_skills = data.key_skills || '';

// AI Analysis - also at top level from Validate Data Completeness
const overall_score = data.overall_score || 'N/A';
const matched_job_title = data.matched_job_title || '';
const candidate_strengths = data.candidate_strengths || [];
const candidate_weaknesses = data.candidate_weaknesses || [];
const risk_level = data.risk_level || 'Unknown';
const risk_explanation = data.risk_explanation || '';
const opportunity_level = data.opportunity_level || 'Unknown';
const opportunity_explanation = data.opportunity_explanation || '';
const ai_adoption_level = data.ai_adoption_level || 'Unknown';
const ai_adoption_explanation = data.ai_adoption_explanation || 'Not evaluated';
const score_justification = data.score_justification || '';
const next_steps = data.next_steps || '';
const recruiter_note = data.recruiter_note || '';
const candidate_questions = data.candidate_questions || [];

// Paycor Analytics - at top level
const source = data.source || '';
const applied_date = data.applied_date || '';
const pipeline_stage = data.pipeline_stage ?? 0;
const candidate_status = data.candidate_status ?? 0;
const candidate_city = data.candidate_city || '';
const candidate_state = data.candidate_state || '';

// Metadata - at top level
const candidateId = data.candidateId || '';
const jobId = data.jobId || '';

// Nested data for job details (from transformData passthrough)
const transformData = data.transformData || {};
const body = transformData.body || {};
const standardizedData = data.standardizedData || {};

// Job details from standardizedData
const jobTitle = standardizedData.jobTitle || matched_job_title || '';
const jobDepartment = standardizedData.jobDepartment || '';
const jobLocation = standardizedData.jobLocation || '';
const jobPayRange = standardizedData.jobPayRange || '';
const jobRemoteStatus = standardizedData.jobRemoteStatus || '';

// Completeness metadata
const completeness = data.completeness || {};

// Operation and timestamps
const operation = data._operation || 'INSERT';
const now = new Date().toISOString();

return [{
  json: {
    // Candidate Info (PRIMARY - from Paycor via Validate Data Completeness)
    full_name: full_name,
    email_address: email_address,
    phone_number: phone_number,
    current_title: current_title,
    years_experience: years_experience,
    key_skills: key_skills,

    // AI Analysis
    matched_job_title: matched_job_title || jobTitle || 'Position',
    overall_score: overall_score,
    candidate_strengths: candidate_strengths,
    candidate_weaknesses: candidate_weaknesses,
    risk_level: risk_level,
    risk_explanation: risk_explanation,
    opportunity_level: opportunity_level,
    opportunity_explanation: opportunity_explanation,
    ai_adoption_level: ai_adoption_level,
    ai_adoption_explanation: ai_adoption_explanation,
    score_justification: score_justification,
    next_steps: next_steps,
    recruiter_note: recruiter_note,
    candidate_questions: candidate_questions,

    // Job Details
    job_title: jobTitle,
    job_department: jobDepartment,
    job_location: jobLocation,
    job_pay_range: jobPayRange,
    job_remote_status: jobRemoteStatus,

    // Paycor Analytics
    source: source,
    applied_date: applied_date,
    pipeline_stage: pipeline_stage,
    candidate_status: candidate_status,
    candidate_city: candidate_city,
    candidate_state: candidate_state,

    // Metadata
    candidateId: candidateId,
    jobId: jobId,
    candidate_entered_database: formatDate(applied_date) || formatDate(now),

    // Completeness
    completeness_status: completeness.status || 'UNKNOWN',
    missing_fields: completeness.missingFields || '',

    // Timestamps
    processed_timestamp: formatDate(now),

    // Operation
    _operation: operation
  }
}];

// Transform Paycor candidate data to workflow format
const items = $input.all();
const results = [];

// Get operation metadata from Filter node
for (const item of items) {
  const candidate = item.json;
  const binaryData = item.binary;
  const candidateName = `${candidate.firstName || ''} ${candidate.lastName || ''}`.trim() || 'Unknown';

  const allJobs = $('Split Jobs Array').all();
  const currentJobId = candidate.jobId;
  const jobData = allJobs.find(j => j.json.id === currentJobId)?.json || {};

  const resumeText = candidate.resumeText || candidate.resume || candidate.resumeContent || candidate.documentText || '';

  const fullJobDescription = [
    jobData?.description || '',
    jobData?.responsibilities || '',
    jobData?.requirements || '',
    jobData?.qualifications || ''
  ].filter(Boolean).join('\n\n') || 'No detailed job description available from Paycor.';

  // Preserve operation metadata from dedup
  const operation = candidate._operation || 'INSERT';
  const compositeKey = candidate._compositeKey || `${candidate.id || candidate.candidateId}_${currentJobId}`;

  results.push({
    json: {
      body: {
        eventType: 'candidate.created',
        candidateId: candidate.id || candidate.candidateId,
        candidateName: candidateName,
        email: candidate.email || candidate.emailAddress || '',
        phone: candidate.mobilePhone || candidate.phone || candidate.phoneNumber || candidate.altPhone || '',
        jobId: currentJobId || 'UNKNOWN',
        appliedDate: candidate.appliedDate || candidate.applicationDate || new Date().toISOString(),
        candidateResume: resumeText,
        jobTitle: jobData?.title || 'Unknown Position',
        jobDescription: fullJobDescription,
        jobDepartment: jobData?.atsDepartment?.title || jobData?.department || 'Unknown Department',
        jobLocation: jobData?.atsLocation ? `${jobData.atsLocation.city || ''}, ${jobData.atsLocation.state || ''}` : (jobData?.location || 'Remote/Unknown'),
        jobPayRange: jobData?.payRange ? `${jobData.payRange.minimum || 'N/A'} - ${jobData.payRange.maximum || 'N/A'} ${jobData.payRange.payPeriod || ''}` : 'Not specified',
        jobRemoteStatus: jobData?.remoteStatus || 'Not specified',

        // NEW: Contact info (primary source - replaces AI extraction)
        paycor_full_name: `${candidate.firstName || ''} ${candidate.lastName || ''}`.trim() || 'Unknown',
        paycor_email: candidate.email || '',
        paycor_phone: candidate.mobilePhone || candidate.phone || '',

        // NEW: Recruiting analytics
        source: candidate.source || 'Unknown',
        applied_date: candidate.createdDate || new Date().toISOString(),
        pipeline_stage: candidate.stage ?? 0,
        candidate_status: candidate.status ?? 3,

        // NEW: Location data
        candidate_city: candidate.city || '',
        candidate_state: candidate.state || ''
      },
      metadata: {
        source: 'Paycor API Polling',
        originalFileName: candidate.resumeFileName || 'N/A',
        apiPollTime: new Date().toISOString(),
        totalCandidatesInBatch: items.length,
        candidateIndex: results.length + 1
      },
      _operation: operation,
      _compositeKey: compositeKey
    },
    binary: binaryData ? { data: binaryData.data } : undefined
  });
}

console.log(`Transformed ${results.length} candidates with job descriptions`);
return results;

// Extract ATS Account ID from API response
const input = $input.first().json;
const response = input.atsApiResponse;

const config = {
  subscriptionKey: input.subscriptionKey,
  legalEntityId: input.legalEntityId,
  baseUrl: input.baseUrl,
  accessToken: input.accessToken,
  clientId: input.clientId,
  clientSecret: input.clientSecret,
  refreshToken: input.refreshToken
};

let atsAccountId = null;

if (response.records && response.records.length > 0) {
  atsAccountId = response.records[0].id;
} else if (response.accounts && response.accounts.length > 0) {
  atsAccountId = response.accounts[0].accountId || response.accounts[0].id;
} else if (response.data && response.data.length > 0) {
  atsAccountId = response.data[0].accountId || response.data[0].id;
} else if (response.accountId) {
  atsAccountId = response.accountId;
} else if (response.id) {
  atsAccountId = response.id;
} else if (Array.isArray(response) && response.length > 0) {
  atsAccountId = response[0].accountId || response[0].id;
}

if (!atsAccountId) {
  console.log('ATS Response:', JSON.stringify(response));
  throw new Error('Could not extract ATS Account ID. Check API response.');
}

return [{
  json: {
    ...config,
    atsAccountId: String(atsAccountId),
    atsAccountTitle: response.records?.[0]?.title || 'Unknown',
    atsApiResponse: response
  }
}];

// Extract access token from response
const response = $input.first().json;
const config = $('Workflow Config').first().json;

if (response.access_token) {
  return [{
    json: {
      ...config,
      accessToken: response.access_token,
      tokenExpiry: response.expires_in,
      newRefreshToken: response.refresh_token || 'Same as before'
    }
  }];
} else {
  return [{
    json: {
      ...config,
      accessToken: null,
      error: response.error || 'Failed to get access token',
      errorDescription: response.error_description || JSON.stringify(response)
    }
  }];
}

// Build token request body from Workflow Config
const config = $('Workflow Config').first().json;

const tokenRequestBody = `grant_type=refresh_token&refresh_token=${encodeURIComponent(config.refreshToken)}&client_id=${encodeURIComponent(config.clientId)}&client_secret=${encodeURIComponent(config.clientSecret)}`;

return [{
  json: {
    ...config,
    tokenRequestBody: tokenRequestBody
  }
}];

// Get ATS Account ID using n8n's built-in HTTP helper
const config = $input.first().json;

const url = `${config.baseUrl}/legalEntities/${config.legalEntityId}/ats/accounts`;

console.log('Calling ATS endpoint:', url);

try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    headers: {
      'Accept': 'application/json',
      'Ocp-Apim-Subscription-Key': config.subscriptionKey,
      'Authorization': `Bearer ${config.accessToken}`
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  const statusCode = response.statusCode;
  const responseBody = response.body;

  console.log('Response status:', statusCode);
  console.log('Response body:', JSON.stringify(responseBody));

  return [{
    json: {
      ...config,
      atsApiStatus: statusCode,
      atsApiResponse: responseBody,
      atsApiSuccess: statusCode >= 200 && statusCode < 300
    }
  }];
} catch (error) {
  console.log('HTTP request error:', error.message);
  return [{
    json: {
      ...config,
      atsApiStatus: 0,
      atsApiResponse: { error: error.message },
      atsApiSuccess: false
    }
  }];
}

// ENHANCED DEDUPLICATION with completeness awareness and error handling
try {
  // Access all merged inputs (processed IDs + candidates)
  const allInputs = $input.all();

  // Handle empty input gracefully
  if (!allInputs || allInputs.length === 0) {
    console.log('WARNING: No inputs received');
    return [];
  }

  // Separate processed rows from candidates based on data structure
  const processedRows = [];
  const candidates = [];

  for (const item of allInputs) {
    // Processed rows have compositeKey, candidates have id/jobId
    if (item.json && item.json.compositeKey) {
      processedRows.push(item);
    } else if (item.json && item.json.id && item.json.jobId) {
      candidates.push(item);
    }
  }

  // Build lookup map with completeness status
  const processedMap = new Map();
  for (const row of processedRows) {
    if (row.json.compositeKey) {
      processedMap.set(row.json.compositeKey, {
        status: row.json.completeness_status || 'COMPLETE',
        rowData: row.json
      });
    }
  }

  // Log processing status
  if (processedMap.size === 0) {
    console.log('⚠️  WARNING: No processed IDs loaded from Excel (Excel node may have failed)');
    console.log('   → Treating all candidates as NEW to prevent blocking workflow');
  } else {
    console.log(`✓ Loaded ${processedMap.size} processed candidates into memory`);
  }
  console.log(`Processing ${candidates.length} new candidates`);

  const results = [];
  let skipComplete = 0;
  let skipIncomplete = 0;
  let newCandidates = 0;
  let updateCandidates = 0;

  for (const candidate of candidates) {
    const candidateId = candidate.json.id;
    const jobId = candidate.json.jobId;
    const compositeKey = `${candidateId}_${jobId}`;

    const existing = processedMap.get(compositeKey);

    if (!existing) {
      // New candidate - process
      newCandidates++;
      results.push({
        ...candidate,
        json: {
          ...candidate.json,
          _operation: 'INSERT',
          _compositeKey: compositeKey
        }
      });
    } else if (existing.status === 'COMPLETE') {
      // Already complete - skip
      skipComplete++;
      console.log(`Skipping complete candidate: ${compositeKey}`);
    } else {
      // Incomplete - allow reprocessing for potential update
      updateCandidates++;
      console.log(`Reprocessing incomplete candidate for update: ${compositeKey}`);
      results.push({
        ...candidate,
        json: {
          ...candidate.json,
          _operation: 'UPDATE',
          _compositeKey: compositeKey,
          _previousData: existing.rowData
        }
      });
    }
  }

  console.log(`Results: ${newCandidates} new, ${updateCandidates} updates, ${skipComplete} complete skipped, ${skipIncomplete} incomplete skipped`);

  return results;

} catch (error) {
  console.error('❌ ERROR in Filter New Candidates:', error.message);
  console.log('   → Returning empty array to prevent workflow failure');
  return [];
}
